export default function handler(req, res) {
  if (req.method === 'GET') {
    // Simulate fetching posts
    const posts = [
      { id: 1, title: 'First Post', content: 'This is the first post' },
      { id: 2, title: 'Second Post', content: 'This is the second post' }
    ];

    res.status(200).json(posts);
  } else if (req.method === 'POST') {
    const { title, content } = req.body;

    if (!title || !content) {
      return res.status(400).json({ error: 'Title and content are required' });
    }

    // Simulate creating a post
    const newPost = {
      id: Date.now(),
      title,
      content,
      createdAt: new Date().toISOString()
    };

    res.status(201).json(newPost);
  } else {
    res.setHeader('Allow', ['GET', 'POST']);
    res.status(405).end(`Method ${req.method} Not Allowed`);
  }
}

export default function handler(req, res) {
  const { id } = req.query;

  if (req.method === 'GET') {
    // Simulate fetching a single post
    const post = {
      id: parseInt(id),
      title: `Post ${id}`,
      content: `This is the content for post ${id}`,
      createdAt: new Date().toISOString()
    };

    res.status(200).json(post);
  } else if (req.method === 'PUT') {
    const { title, content } = req.body;

    // Simulate updating a post
    const updatedPost = {
      id: parseInt(id),
      title: title || `Post ${id}`,
      content: content || `Updated content for post ${id}`,
      updatedAt: new Date().toISOString()
    };

    res.status(200).json(updatedPost);
  } else if (req.method === 'DELETE') {
    // Simulate deleting a post
    res.status(200).json({ message: `Post ${id} deleted successfully` });
  } else {
    res.setHeader('Allow', ['GET', 'PUT', 'DELETE']);
    res.status(405).end(`Method ${req.method} Not Allowed`);
  }
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: 'Inter', sans-serif;
  line-height: 1.6;
  color: #333;
}

.app-container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 20px;
}

header {
  padding: 20px 0;
  border-bottom: 1px solid #eee;
  margin-bottom: 40px;
}

header h1 {
  margin-bottom: 10px;
}

nav a {
  margin-right: 20px;
  text-decoration: none;
  color: #0070f3;
}

nav a:hover {
  text-decoration: underline;
}

.posts-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 20px;
  margin-top: 20px;
}

.post-card {
  border: 1px solid #eee;
  padding: 20px;
  border-radius: 8px;
}

.post-card h2 {
  margin-bottom: 10px;
}

.post-card a {
  text-decoration: none;
  color: #333;
}

.post-card a:hover {
  color: #0070f3;
}

.comments {
  margin-top: 30px;
}

.comment {
  border: 1px solid #eee;
  padding: 15px;
  margin-bottom: 15px;
  border-radius: 8px;
}

.comment h3 {
  margin-bottom: 5px;
  font-size: 16px;
}

.comment small {
  color: #666;
}

.error-page {
  text-align: center;
  padding: 100px 20px;
}

.error-page h1 {
  margin-bottom: 20px;
  font-size: 2rem;
}

.error-page p {
  margin-bottom: 30px;
  font-size: 1.1rem;
}

button {
  background: #0070f3;
  color: white;
  border: none;
  padding: 10px 20px;
  border-radius: 5px;
  cursor: pointer;
  font-size: 16px;
}

button:hover {
  background: #0051a2;
}

