import { NextResponse, type NextRequest } from 'next/server';
import { updatePostSchema, type ApiPost } from '../../../../lib/posts';

interface PostRouteContext {
  params: Promise<{
    id: string;
  }>;
}

function parsePostId(rawId: string): number | null {
  const id = Number.parseInt(rawId, 10);

  return Number.isNaN(id) ? null : id;
}

export async function GET(_request: NextRequest, { params }: PostRouteContext) {
  const { id: rawId } = await params;
  const id = parsePostId(rawId);

  if (id === null) {
    return NextResponse.json({ error: 'Invalid post id' }, { status: 400 });
  }

  const post: ApiPost = {
    id,
    title: `Post ${id}`,
    content: `This is the content for post ${id}`,
    createdAt: post.createdAt ?? new Date().toISOString(),
  };

  return NextResponse.json(post);
}

export async function PUT(request: NextRequest, { params }: PostRouteContext) {
  const { id: rawId } = await params;
  const id = parsePostId(rawId);

  if (id === null) {
    return NextResponse.json({ error: 'Invalid post id' }, { status: 400 });
  }

  const body: unknown = await request.json();
  const parsed = updatePostSchema.safeParse(body);

  if (!parsed.success) {
    return NextResponse.json({ error: 'Invalid request body' }, { status: 400 });
  }

  const existingPost = POSTS.get(id);

  const updatedPost: ApiPost = {
    id,
    title: parsed.data.title ?? `Post ${id}`,
    content: parsed.data.content ?? `Updated content for post ${id}`,
    updatedAt: new Date().toISOString(),
  };

  return NextResponse.json(updatedPost);
}

export async function DELETE(_request: NextRequest, { params }: PostRouteContext) {
  const { id: rawId } = await params;
  const id = parsePostId(rawId);

  if (id === null) {
    return NextResponse.json({ error: 'Invalid post id' }, { status: 400 });
  }

  return NextResponse.json({ message: `Post ${id} deleted successfully` });
}

