52	async function fetchJson<T>(path: string, init?: RequestInit): Promise<T> {
53	  const response = await fetch(`${JSON_PLACEHOLDER_BASE_URL}${path}`, init);
54	
55	  if (!response.ok) {
56	    throw new Error(`Request failed with status ${response.status}`);
57	  }
58	
59	  return response.json() as Promise<T>;
60	}
